function solve(n, edges, k) {
    if (edges.length === 0) {
        return 0;
    }

    let max_time = 0;
    for (const [u, v, time] of edges) {
        if (time > max_time) {
            max_time = time;
        }
    }

    function count_components(t) {
        const adj = new Array(n).fill().map(() => []);
        for (const [u, v, time] of edges) {
            if (time > t) {
                adj[u].push(v);
                adj[v].push(u);
            }
        }

        const visited = new Array(n).fill(false);
        let count = 0;

        for (let i = 0; i < n; i++) {
            if (!visited[i]) {
                count++;
                const queue = [i];
                visited[i] = true;

                while (queue.length > 0) {
                    const node = queue.shift();
                    for (const neighbor of adj[node]) {
                        if (!visited[neighbor]) {
                            visited[neighbor] = true;
                            queue.push(neighbor);
                        }
                    }
                }
            }
        }

        return count;
    }

    if (count_components(-1) >= k) {
        return 0;
