func solve(n int64, edges [][]int64, k int64) int64 {
    if len(edges) == 0 {
        return 0
    }

    maxTime := int64(0)
    for _, edge := range edges {
        if edge[2] > maxTime {
            maxTime = edge[2]
        }
    }

    countComponents := func(t int64) int64 {
        adj := make([][]int64, n)
        for i := int64(0); i < n; i++ {
            adj[i] = make([]int64, 0)
        }
        for _, edge := range edges {
            u, v, time := edge[0], edge[1], edge[2]
            if time > t {
                adj[u] = append(adj[u], v)
                adj[v] = append(adj[v], u)
            }
        }
        visited := make([]bool, n)
        count := int64(0)
        for i := int64(0); i < n; i++ {
            if !visited[i] {
                count++
                queue := []int64{i}
                visited[i] = true
                for len(queue) > 0 {
                    node := queue[0]
                    queue = queue[1:]
                    for _, neighbor := range adj[node] {
                        if !visited[neighbor] {
                            visited[neighbor] = true
                            queue = append(queue, neighbor)
                        }
                    }
                }
            }
        }
        return count
    }

    initialCount := countComponents(-1)
    if initialCount >= k {
        return 0
    }

    low := int64(0)
    high := maxTime
    answer := maxTime

    for low <= high {
        mid := (low + high) / 2
        components := countComponents(mid)
        if components >= k {
            answer = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }

    return answer
}
